import argparse
from kafka.admin import KafkaAdminClient, NewTopic

def create_topic(admin_client, topic_name, num_partitions=1, replication_factor=1):
    topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor)
    try:
        admin_client.create_topics([topic])
        print(f"Topic {topic_name} created successfully.")
    except Exception as e:
        print(f"Failed to create topic {topic_name}: {e}")

def list_topics(admin_client):
    topics = admin_client.list_topics()
    if not topics:
        print("No topics found.")
    else:
        print("Topics in the cluster:")
        for topic in topics:
            print(topic)

if __name__ == "__main__":
    parser = argparse.ArgumentParser(description="Kafka Cluster Administration Tool")
    subparsers = parser.add_subparsers(dest='command')

    create_parser = subparsers.add_parser('create', help='Create a new Kafka topic')
    create_parser.add_argument('--topic-name', required=True, help='Name of the topic to create')
    create_parser.add_argument('--partitions', type=int, default=1, help='Number of partitions (default: 1)')
    create_parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor (default: 1)')

    list_parser = subparsers.add_parser('list', help='List all Kafka topics')

    args = parser.parse_args()

    admin_client = KafkaAdminClient(bootstrap_servers='localhost:9092')  # Update with your Kafka broker address

    if args.command == 'create':
        create_topic(admin_client, args.topic_name, args.partitions, args.replication_factor)
    elif args.command == 'list':
        list_topics(admin_client)